"""Trading strategies: Momentum, MeanReversion, Combined."""

from abc import ABC, abstractmethod
import math


class Strategy(ABC):
    """Base class for all trading strategies."""

    def __init__(self, name: str, params: dict):
        self.name = name
        self.params = params

    @abstractmethod
    def generate_signals(self, prices: list[dict]) -> list[dict]:
        """Return list of {date, signal} where signal in {1, 0, -1}."""
        ...


class MomentumStrategy(Strategy):
    """Trend-following strategy based on lookback period returns."""

    def __init__(self, params: dict):
        super().__init__("Momentum", params)
        self.lookback = params.get("lookback_period", 20)
        self.entry_threshold = params.get("entry_threshold", 0.02)
        self.exit_threshold = params.get("exit_threshold", -0.01)

    def generate_signals(self, prices: list[dict]) -> list[dict]:
        signals = []
        closes = [p["close"] for p in prices]

        for i in range(len(prices)):
            if i < self.lookback:
                signals.append({"date": prices[i]["date"], "signal": 0})
                continue

            ret = (closes[i] - closes[i - self.lookback]) / closes[i - self.lookback]

            if ret > self.entry_threshold:
                sig = 1
            elif ret < self.exit_threshold:
                sig = -1
            else:
                sig = 0

            signals.append({"date": prices[i]["date"], "signal": sig})

        return signals


class MeanReversionStrategy(Strategy):
    """Mean-reversion strategy using Bollinger Bands / z-score."""

    def __init__(self, params: dict):
        super().__init__("MeanReversion", params)
        self.lookback = params.get("lookback_period", 20)
        self.entry_zscore = params.get("entry_zscore", -2.0)
        self.exit_zscore = params.get("exit_zscore", 0.0)

    def generate_signals(self, prices: list[dict]) -> list[dict]:
        signals = []
        closes = [p["close"] for p in prices]

        for i in range(len(prices)):
            if i < self.lookback:
                signals.append({"date": prices[i]["date"], "signal": 0})
                continue

            window = closes[i - self.lookback: i]
            mean = sum(window) / len(window)
            std = math.sqrt(sum((x - mean) ** 2 for x in window) / len(window))

            if std == 0:
                signals.append({"date": prices[i]["date"], "signal": 0})
                continue

            zscore = (closes[i] - mean) / std

            if zscore <= self.entry_zscore:
                sig = 1   # buy (price is low relative to mean)
            elif zscore >= -self.entry_zscore:
                sig = -1  # sell (price is high relative to mean)
            elif abs(zscore) <= abs(self.exit_zscore) + 0.5:
                sig = 0   # close position (near mean)
            else:
                sig = 0

            signals.append({"date": prices[i]["date"], "signal": sig})

        return signals


class CombinedStrategy(Strategy):
    """Weighted combination of Momentum and MeanReversion signals."""

    def __init__(self, params: dict, momentum_params: dict, mr_params: dict):
        super().__init__("Combined", params)
        self.momentum_weight = params.get("momentum_weight", 0.5)
        self.mr_weight = params.get("mean_reversion_weight", 0.5)
        self.momentum = MomentumStrategy(momentum_params)
        self.mean_reversion = MeanReversionStrategy(mr_params)

    def generate_signals(self, prices: list[dict]) -> list[dict]:
        mom_signals = self.momentum.generate_signals(prices)
        mr_signals = self.mean_reversion.generate_signals(prices)

        combined = []
        for m, r in zip(mom_signals, mr_signals):
            score = (m["signal"] * self.momentum_weight +
                     r["signal"] * self.mr_weight)

            if score > 0.3:
                sig = 1
            elif score < -0.3:
                sig = -1
            else:
                sig = 0

            combined.append({"date": m["date"], "signal": sig})

        return combined


def create_strategies(config: dict) -> list[Strategy]:
    """Instantiate all strategies from config."""
    strats = config["strategies"]
    return [
        MomentumStrategy(strats["momentum"]),
        MeanReversionStrategy(strats["mean_reversion"]),
        CombinedStrategy(
            strats["combined"],
            strats["momentum"],
            strats["mean_reversion"],
        ),
    ]

