"""Trading strategies: Momentum, MeanReversion, Combined."""
from dataclasses import dataclass


@dataclass
class Signal:
    date: str
    action: str  # "BUY", "SELL", "HOLD"
    strength: float  # 0.0 to 1.0


def momentum(bars: list[dict], lookback: int = 20) -> list[Signal]:
    """Buy when price is above N-day high, sell when below N-day low."""
    signals = []
    for i, bar in enumerate(bars):
        if i < lookback:
            signals.append(Signal(bar["date"], "HOLD", 0.0))
            continue

        window = [b["close"] for b in bars[i - lookback:i]]
        high = max(window)
        low = min(window)
        mid = (high + low) / 2
        price = bar["close"]

        if price > high:
            strength = min((price - high) / (high * 0.01 + 1e-9), 1.0)
            signals.append(Signal(bar["date"], "BUY", abs(strength)))
        elif price < low:
            strength = min((low - price) / (low * 0.01 + 1e-9), 1.0)
            signals.append(Signal(bar["date"], "SELL", abs(strength)))
        else:
            signals.append(Signal(bar["date"], "HOLD", 0.0))

    return signals


def mean_reversion(bars: list[dict], lookback: int = 20, threshold: float = 1.5) -> list[Signal]:
    """Buy when price is below mean - threshold*std, sell when above mean + threshold*std."""
    signals = []
    for i, bar in enumerate(bars):
        if i < lookback:
            signals.append(Signal(bar["date"], "HOLD", 0.0))
            continue

        window = [b["close"] for b in bars[i - lookback:i]]
        mean = sum(window) / len(window)
        std = (sum((x - mean) ** 2 for x in window) / len(window)) ** 0.5
        if std < 1e-9:
            signals.append(Signal(bar["date"], "HOLD", 0.0))
            continue

        z = (bar["close"] - mean) / std

        if z < -threshold:
            signals.append(Signal(bar["date"], "BUY", min(abs(z) / 3, 1.0)))
        elif z > threshold:
            signals.append(Signal(bar["date"], "SELL", min(abs(z) / 3, 1.0)))
        else:
            signals.append(Signal(bar["date"], "HOLD", 0.0))

    return signals


def combined(bars: list[dict]) -> list[Signal]:
    """Blend Momentum and MeanReversion signals with equal weight."""
    mom_signals = momentum(bars)
    mr_signals = mean_reversion(bars)
    signals = []

    action_score = {"BUY": 1, "HOLD": 0, "SELL": -1}

    for m, r in zip(mom_signals, mr_signals):
        score = (action_score[m.action] * m.strength + action_score[r.action] * r.strength) / 2
        if score > 0.1:
            action = "BUY"
        elif score < -0.1:
            action = "SELL"
        else:
            action = "HOLD"
        signals.append(Signal(m.date, action, abs(score)))

    return signals


STRATEGIES = {
    "Momentum": momentum,
    "MeanReversion": mean_reversion,
    "Combined": combined,
}
